// Controller using DTO
@RestController
@RequestMapping("/api/users")
public class UserController {

    @Autowired
    private UserService userService;

    @PutMapping("/{id}")
    public ResponseEntity<User> updateUser(
            @PathVariable Long id,
            @Valid @RequestBody UserUpdateDTO updateDTO,
            @AuthenticationPrincipal UserDetails currentUser) {

        // Verify user can only modify their own profile
        if (!currentUser.getUsername().equals(
                userService.findById(id).getUsername())) {
            throw new AccessDeniedException("Cannot modify other user's profile");
        }

        User updatedUser = userService.updateUser(id, updateDTO);
        return ResponseEntity.ok(updatedUser);
    }
}

// Service layer - Manual field mapping
@Service
public class UserService {

    @Autowired
    private UserRepository userRepository;

    @Transactional
    public User updateUser(Long id, UserUpdateDTO dto) {
        User user = userRepository.findById(id)
            .orElseThrow(() -> new ResourceNotFoundException("User not found"));

        // EXPLICIT field mapping - only safe fields
        user.setUsername(dto.getUsername());
        user.setEmail(dto.getEmail());
        user.setBio(dto.getBio());
        // role, isActive, accountBalance remain unchanged!

        return userRepository.save(user);
    }
}

