public class GlobalControllerAdvice {

    @InitBinder
    public void initBinder(WebDataBinder binder) {
        // Blacklist sensitive fields from binding
        binder.setDisallowedFields(
            "id", "role", "isActive", "accountBalance", 
            "createdAt", "password", "isAdmin", "permissions"
        );
    }
