from django.db import models
from django.contrib.auth.models import AbstractUser

class User(AbstractUser):
    email = models.EmailField(unique=True)
    bio = models.TextField(max_length=500, blank=True)

    # SENSITIVE FIELDS - Should not be modifiable via API
    is_admin = models.BooleanField(default=False)
    account_balance = models.DecimalField(
        max_digits=10, decimal_places=2, default=0.00
    )
    role = models.CharField(
        max_length=20,
        choices=[('user', 'User'), ('moderator', 'Moderator'), ('admin', 'Admin')],
        default='user'
    )
    created_at = models.DateTimeField(auto_now_add=True)

    class Meta:
        db_table = 'users'

# VULNERABLE: Using ModelForm with '__all__' or 'exclude'
class VulnerableUserForm(forms.ModelForm):
    class Meta:
        model = User
        fields = '__all__'  # ❌ DANGEROUS: Exposes ALL fields including is_admin, role
        # OR
        exclude = ['password']  # ❌ DANGEROUS: Blocklist approach misses new fields

# SECURE: Explicit allowlist with ModelForm
class SafeUserForm(forms.ModelForm):
    class Meta:
        model = User
        fields = ['username', 'email', 'bio']  # ✅ Only safe fields
        # Sensitive fields (is_admin, role, account_balance) are NOT included

