from rest_framework import viewsets, permissions
from rest_framework.decorators import action
from rest_framework.response import Response

class UserViewSet(viewsets.ModelViewSet):
    queryset = User.objects.all()
    serializer_class = UserSerializer
    permission_classes = [permissions.IsAuthenticated]

    def get_permissions(self):
        if self.action in ['update', 'partial_update']:
            # Users can only update their own profiles
            return [permissions.IsAuthenticated(), IsOwnerOrAdmin()]
        return super().get_permissions()

    def update(self, request, *args, **kwargs):
        # Additional validation: prevent privilege escalation attempts
        if 'is_admin' in request.data or 'role' in request.data:
            return Response(
                {'error': 'Cannot modify admin status or role'},
                status=400
            )
        return super().update(request, *args, **kwargs)

# Custom permission class
class IsOwnerOrAdmin(permissions.BasePermission):
    def has_object_permission(self, request, view, obj):
        return obj.id == request.user.id or request.user.is_admin
